INSERT INTO `ai_question_record` VALUES (2978, 95, 'a5ef98502ced4404add29c2bbe1822c0', 1, '????????', 1, '根据您提供的参考资料，内容涉及的是东汉末年的历史事件。因此，这些事件属于东汉末年时期。如果这些内容在广义的三国故事范畴内，那么它们也可以被看作是三国时期的一部分，因为三国时期是从220年魏国建立开始，到280年晋朝灭吴结束，而东汉末年则是这一历史阶段的前奏。但根据您的要求，最准确的归属是东汉末年。', '2026-05-06 09:27:44');
