INSERT INTO `ai_question_record` VALUES (3687, 95, '3216c7d6c61844f89b2b400a9635298a', 1, '????????', 1, '根据您提供的信息，这些内容涉及的历史时期较为广泛，以下是具体分析：\n\n1. “东汉末年≈184-220”：根据参考资料1中提到的“东汉末年”，这显然属于东汉末年的时期，即184-220年之间。\n\n2. “三国时期≈220（魏建立）-280（晋灭吴）”：参考资料2中提到的“三国时期”，广义上可以包括三国时期，即220年（魏建立）至280年（晋灭吴）。\n\n3. “西晋≈265-316”：参考资料3中提到的“西晋”，属于西晋时期，即265-316年。\n\n总结：\n- 东汉末年：明确属于东汉末年，时间约为184-220年。\n- 三国时期：广义上属于三国时期，时间约为220-280年。\n- 西晋：明确属于西晋时期，时间约为265-316年。\n\n如需进一步核查或详细探讨，请提供具体的历史事件或人物，以便给出更精确的归属。', '2026-05-06 09:28:12');
