INSERT INTO `ai_question_record` VALUES (4297, 95, '664ad8b552e3472b859f8d0f2c81811d', 1, '????????', 1, '根据您提供的参考资料，这些内容主要描述了东汉末年的社会状况和历史背景，因此这些内容属于东汉末年这一时期。东汉末年（184-220）是中国历史上的一个重要时期，这一时期发生了黄巾起义，是三国时期的直接导火索，标志着汉朝的衰落和三国时代的开始。\n\n所以，根据参考资料，这些内容最准确的归属是东汉末年。如果需要考虑广义的“三国故事范畴”，则可以将其视为与三国时期相关的历史背景材料。', '2026-05-06 15:52:28');
