INSERT INTO `ai_question_record` VALUES (5025, 95, '782ed48d50f84a44b0be89cd0001457a', 1, '????????', 1, '根据您提供的参考资料，内容涉及的是东汉末年的历史事件和人物。具体来说，参考资料中提到了“东汉末年”和“东汉末年的乱世”，这表明所述内容属于东汉末年这一时期。\n\n因此，针对您的问题“属于哪个朝代/时期/是否属于三国时期”，可以回答如下：\n\n所述内容属于东汉末年，即公元184年至220年之间。虽然东汉末年是三国时期的前奏，但严格来说，它并不属于三国时期。三国时期通常指的是220年魏国建立至280年晋灭吴的这段时间。所以，虽然东汉末年是三国故事范畴的一部分，但直接归属应为东汉末年。', '2026-05-06 19:21:00');
