INSERT INTO `ai_question_record` VALUES (5686, 95, 'ee5f65ba8f7d48838826b88dbaedb7e6', 1, '????????', 1, '根据您提供的参考资料，内容主要涉及东汉末年的社会状况和历史背景，因此可以归属为东汉末年。\n\n具体分析如下：\n\n1. 参考资料中提到“东汉末年”，直接点明了时间背景。\n2. 描述了当时的社会动荡和历史事件，符合东汉末年的历史特征。\n\n所以，根据您提供的资料，该内容属于东汉末年。如果需要更广泛的历史背景，可以考虑将其纳入“广义三国故事范畴”，但这需要明确区分。', '2026-05-06 20:03:04');
