INSERT INTO `person` VALUES (1, '曹操', '字孟德', '东汉', '政治家、军事家、诗人，统一了北方、挟天子以令诸侯，戎马一生。曹操父亲曹嵩为宦官曹腾养子，曹腾为汉相曹参之后。曹操谥武王，曹丕称帝后，追尊他为武皇帝，史称魏武帝。曹操在北方屯田，兴修水利，解决了军粮缺乏的问题，对农业生产的恢复有一定作用；用人唯才，罗致地主阶级中下层人物，抑制豪强，加强集权。颂令收田租亩四升，戶出绢二匹、锦二斤，为日后的租庸调之始。所统治的地区社会经济得到恢复和发展。草创九品官人法。精兵法，著《孙子略解》、《兵书接要》等书。善诗歌，《蒿里行》、《观沧海》等篇，抒发自己的政治抱负，并反映汉末人民的苦难生活，气魄雄伟，慷慨悲凉。散文亦清峻整洁。著作有《魏武帝集》。葬于高陵。', '/api/uploads/images/20260301/8f79f6cd081145abb1ac9366804d80d1.png', 1, '2026-03-01 10:44:17', '2026-05-05 15:18:08');
INSERT INTO `person` VALUES (2, '刘备', '字玄德', '蜀国', '蜀汉的开国皇帝，相传是汉景帝之子中山靖王刘胜的后代。刘备少年丧父，与母亲贩鞋织草席为生。黄巾起义时，刘备组织义兵，随政府军剿除黄巾，有功，任安喜县尉，不久因鞭打督邮弃官。后诸侯割据，刘备势力弱小，经常寄人篱下，先后投靠过公孙瓒、曹操、袁绍、刘表等人，几经波折，却仍无自己的地盘。赤壁之战之际，刘备联吴抗曹，取得胜利，从东吴处“借”到荆州，迅速发展起来，吞并益州，占领汉中，建立蜀汉政权。后关羽战死，荆州被孙权夺取，刘备于称帝后伐吴，在夷陵之战中被陆逊击败，病逝于白帝城，临终托孤于诸葛亮。', '/api/uploads/images/20260301/300ebd7766054f1db69d48cc170b074c.png', 2, '2026-03-01 10:44:17', '2026-05-05 15:22:29');
INSERT INTO `person` VALUES (3, '孙权', '字仲谋', '吴国', '　　孙坚之子，孙策之弟。东汉建安五年，兄孙策病死，孙权继位吴侯、讨逆将军，领会稽太守，开始统领江东。他击败了黄祖。后东吴联合刘备，于赤壁击溃了曹操军。东吴后来又和曹操军在合肥附近鏖战，并从刘备手中夺回荆州、杀死关羽、大破刘备的讨伐军。曹丕称帝后孙权先向北方称臣，后自己建吴称帝，迁都建业。孙权称帝后曾大规模派人航海，加强对夷州的联系。又设置农官，实行屯田；并在山越地区设立郡县，促进了江南土地的开发。晚年的孙权日益骄奢，宠信吕壹，赋役繁重、刑罚残酷。立嗣之争，孙权也犯下极大错误，多数名臣死于非命。自孙登夭折后，孙权先是废了孙和，又赐死孙霸，最后立幼子孙亮，这为日后的吴宫政变埋下了祸根。孙权病逝后谥号大皇帝，史称东吴大帝。', '/api/uploads/images/20260301/f5a0a9548ccb4f4d9eb128fa642827eb.png', 3, '2026-03-01 10:44:17', '2026-05-05 15:22:42');
INSERT INTO `person` VALUES (4, '诸葛亮', '字孔明', '蜀国', '政治家、军事家，被誉为“千古良相”的典范。父母早亡，由叔父玄抚养长大，后因徐州之乱，避乱荆州，潜心向学，淡泊明志。后受刘备三顾之礼，提出著名的《隆中对》，策动孙、刘联盟，于赤壁之战中大破曹操，奠定三国鼎立的基础。蜀汉建立，拜为丞相。刘备伐吴失败，受托孤于永安，辅佐幼主，外联东吴，内修政理，南征平叛，北抗强魏。为完成统一中原，兴复汉室的大业，先后五次进攻魏国，在治国、治军等方面发挥了非凡的才能，是以民用其力，百姓不忿；又推演兵法，作“八阵图”，造损益连弩、木牛流马，与名将司马懿、张郃等交锋，屡操胜算，最后一次北伐时采取分兵屯田之策，与司马懿大军相持百余日，但不幸因积劳成疾而逝世，享年五十四岁，谥曰忠武侯。其“鞠躬尽力，死而后已”的高尚品格，千百年来一直为人们所敬仰和怀念。', '/api/uploads/images/20260301/d07b5710821d41de974f89d5fcb472f5.png', 4, '2026-03-01 10:44:17', '2026-05-05 15:22:58');
INSERT INTO `person` VALUES (5, '关羽', '字云长', '蜀国', '前将军。本字长生，亡命奔涿郡。与张飞追随刘备征战，当刘备为平原相时，他们俩为别部司马。二人与刘备寝则同床，恩若兄弟。稠人广坐则侍立终日。随同曹操和刘备讨吕布于下邳，事后为朝廷封为中郎将。当刘备袭杀曹操的徐州刺史车冑后，以关羽镇下邳太守。曹操东征破刘备，关羽被俘，被拜为偏将军，对他礼遇很优厚。白马之战时关羽万军中刺敌主帅颜良，被封为汉寿亭侯，报了曹操之恩后便告辞，寻找刘备。长阪之战刘备败北，抄近路赴汉津与关羽的数百只船汇合至江夏。赤壁之战孙刘联军胜利后，关羽在其后的江陵之战中绝北道，阻隔曹操的援军，为周瑜能攻下江陵创造有利的条件。事后遙领襄阳太守、拜为荡寇将军。诸葛亮等人入蜀增援刘备，关羽便镇荊州。刘备自立为汉中王，被拜为前将军，假节钺。关羽乘汉水暴涨之机出兵襄樊，更在于禁七军为水所淹乘船进攻，梁、郏、陆浑各县的盗贼有些远远地领受了关羽的官印封号，威震华夏；曹操一度想迁都避其锋芒。后因孙权背盟投曹，后方为吕蒙所破，关羽便退兵，但终为孙权军所擒杀。', '/api/uploads/images/20260301/8a22f60ede494ed38b25be66defe4a6c.png', 5, '2026-03-01 10:44:17', '2026-05-05 15:23:17');
INSERT INTO `person` VALUES (6, '张飞', '字翼德', '蜀国', '车骑将军、司隶校尉。年少时与关羽投靠刘备，三人恩如兄弟。刘备被公孙瓒表为平原相后刘备以其为別部司马。袁术讨刘备，刘备以张飞守下邳，但他与陶谦旧部曹豹发生冲突，招致丹杨兵开门引吕布破徐州。娶十三、四岁的夏侯氏为妻。曹操降荊州后引骑追击，刘备于长阪败逃，张飞引二十余骑，拆水断桥，终退曹军。从征赤壁和南郡之战，后被封为宜都太守、征虏将军、新亭侯。入蜀讨刘璋，于江州擒巴郡严颜，再定德阳、巴西等地。刘备得益州后赐张飞金五百斤，银千斤，钱五千万，锦千匹，兼领巴西太守。引军迂回至张郃军背后，于瓦口击败他。汉中之战时屯下辩，但友军吴兰为曹洪所破，被迫退走。刘备为汉中王，拜为右将军，假节。刘备称帝，封张飞为车骑将军，兼任司隶校尉，进封为西乡侯。刘备准备伐吴，张飞本率万人从中汇合，但为帐下将张达、范强所杀，他们持其首顺流而奔孙权。谥号为桓侯。', '/api/uploads/images/20260301/3c37528951804e1e9f2d3e56f86e1b90.png', 6, '2026-03-01 10:44:17', '2026-05-05 15:29:06');
INSERT INTO `person` VALUES (7, '赵云', '字子龙', '蜀国', '以英勇善战、一身是胆著称。初为本郡所举，将义从吏兵诣公孙瓒。时袁绍称冀州牧，瓒深忧州人之从绍也，善云来附，遂与瓒征讨。时先主亦依讬瓒，每接纳云，云得深自结讬。瓒遣先主为田楷拒袁绍，云遂随从，为先主主骑。云以兄丧，辞瓒暂归，先主知其不反，捉手而别，云辞曰：“终不背德也。”先主就袁绍，云见于邺。先主与云同床眠卧，密遣云合募得数百人，皆称刘左将军部曲，绍不能知。遂随先主至荆州。夏侯惇战于博望，生获夏侯兰。兰是云乡里人，少小相知，云白先主活之，荐兰明于法律，以为军正。及先主为曹公所追于当阳长阪，弃妻子南走，云身抱弱主，保护甘夫人，皆得免难。迁为牙门将军。先主入蜀，云留荆州。从平江南，以为偏将军，领桂阳太守，代赵范。范寡嫂曰樊氏，有国色，范欲以配云。云固辞不许。先主入益州，云领留营司马。时先主孙夫人欲将后主还吴，云与张飞勒兵截江，乃得后主还。先主自葭萌还攻刘璋，召诸葛亮。亮率云与张飞等俱溯江西上，平定郡县。至江州，分遣云从外水上江阳，与亮会于成都。成都既定，以云为翊军将军。孙权袭荆州，先主大怒，欲讨权。云谏止，不从。乃留云督江州。先主失利于秭归，云进兵至永安，吴军已退。建兴元年，为中护军、征南将军，封永昌亭侯，迁镇东将军。五年，随诸葛亮驻汉中。明年，亮出军，扬声由斜谷道，曹真遣大众当之。亮令云与邓芝往拒，而身攻祁山。云、芝兵弱敌强，失利于箕谷，然敛众固守，不至大败。军退，贬为镇军将军。七年卒，追谥顺平侯。', '/api/uploads/images/20260301/d1cc81a8a3a64009b7ef3a02a2a95a1c.png', 7, '2026-03-01 10:44:17', '2026-05-05 15:29:27');
INSERT INTO `person` VALUES (8, '马超', '字孟起', '蜀国', '马腾遣马超随钟繇讨郭援于平阳，马超为飞矢所中，乃以布带裹好受伤的小腿继续战斗，终破袁军。马腾入朝为卫尉，拜马超为偏将军，封都亭侯，代领其众。关中之战时曾追击为渡河的己军而殿后的曹操，其骑兵箭下如雨，但为许褚保护曹操才得免于难；也多次以骑兵冲阵让曹军无法立营。后中贾诩的离间计而为曹操所败，马超和韩遂逃往凉州。曹操退兵前杨阜就说马超有布、信之勇，甚得羌、胡之心，退兵的话陇上恐怕不再为国家所有。次年曹操诛马腾，夷三族。卷土重来的马超率诸戎，得陇上诸郡县响应，破凉州州治冀城，但因杀刺史韦康而招致凉州州人报仇，为杨阜等所破，投靠张鲁。知其不足与大事，且受其将杨昂抵毀，改投刘备，让被围的刘璋军震恐，加速其投降。定成都后拜为平西将军，督临沮。屯下辩时因己军吴兰为曹洪击破，与张飞一起被迫退兵。刘备得汉中后，以马超为首的一百二十名大臣联名上疏，劝刘备进位汉中王。刘备自立为汉中王后，拜马超为左将军，假节。刘备称帝后迁为骠骑将军，领凉州牧，进封斄乡侯。死前上奏请刘备照顾马家。追谥号为威侯。', '/api/uploads/images/20260301/5d30af34551e41478fc51796ee09ec4a.png', 8, '2026-03-01 10:44:17', '2026-05-05 15:29:52');
INSERT INTO `person` VALUES (9, '黄忠', '字汉升', '蜀国', '初为刘表帐下中郎将，与刘表侄子刘磐共守长沙攸县。刘琮降曹后为曹操任为代理裨将军，统属于长沙太守韩玄，刘备平荊南四郡后改为刘备属下。跟随刘备入蜀，作战时常先登陷陈，勇毅冠三军。益州平后拜为讨虏将军。汉中之战时，黄忠军于定军山斩夏侯渊，迁征西将军。刘备自封为为汉中王后升为后将军，和关羽等齐位，赐爵关内侯。建安二十五年卒，追谥刚侯。', '/api/uploads/images/20260301/e695b2c334e84a4aa9953ab5fb01215d.png', 9, '2026-03-01 10:44:17', '2026-05-05 15:30:24');
INSERT INTO `person` VALUES (10, '魏延', '字文长', '蜀国', '征西大将军、前军师、凉州刺史。以部曲随刘备入蜀，数有战功，迁牙门将军。刘备为汉中王，欲以重将镇汉川，众论以为必是张飞，张飞亦以心自许，结果拔魏延为督汉中镇远将军、领汉中太守，全军尽惊。诸葛亮驻汉中，以魏延为督前部，领丞相司马、凉州刺史。魏延西入羌中破郭淮费曜于阳谿，迁为前军师、征西大将军，假节，进封南郑侯。魏延每随诸葛亮从征，辄欲请兵万人，与诸葛亮异道会于潼关，如韩信故事，但诸葛亮制而不许。魏延常谓诸葛亮为怯，叹恨己才用之不尽；与杨仪势成水火。诸葛亮病困，令魏延断后，姜维次之；若延或不从命，军便自发。魏延本无意北降魏而南还，但欲除杀杨仪等，冀时论必当以代诸葛亮。他们各相表叛逆，一日之中，羽檄交至。魏延先至据南谷口，遣兵逆击杨仪等，王平喝斥，魏延军士众知曲在魏延，而不肯用命，军皆散。延独与其子数人逃亡，奔汉中。杨仪遣马岱追斩之，夷三族。', '/api/uploads/images/20260301/dcc5f6db67f44927931536fbb081be28.png', 91, '2026-03-01 10:44:17', '2026-05-06 10:16:26');
INSERT INTO `person` VALUES (11, '周瑜', '字公瑾', '吴国', '自幼与孙策交好，孙策于袁术麾下初崛起时曾随之扫荡江东。后来回去镇守丹阳。袁术心慕周瑜的才干，欲聘周瑜为将，但是周瑜以袁术难成大事而拒绝。其后设法投奔孙策，为中郎将，孙策相待甚厚，又同时迎娶有「国色」之称的二乔，成为连襟。孙策遇刺身亡后，周瑜与张昭一起共同辅佐孙权，为中护军，执掌军政大事。赤壁大战期间，力主拒曹，而指挥全军在乌林迎击曹军取得胜利。赤壁大战之后，周瑜谏议孙权将刘备安抚在吴郡，以美女和玩物消磨其意志，但孙权未采纳。孙权后来采纳周瑜的谏议，拟出兵攻取蜀地，消灭张鲁，然后消灭曹操，周瑜在江陵进行军事准备时死于巴陵，时年三十六岁。孙权曾为其素服吊丧。周瑜性情开朗，气度宽宏，深得维恩显着。精通乐律，即使在醉酒时也能听出音律的错误。', '/api/uploads/images/20260301/cf681d9dc46a42d68804479b2d652b4f.png', 90, '2026-03-01 10:44:17', '2026-05-06 10:16:09');
INSERT INTO `person` VALUES (12, '陆逊', '字伯言', '吴国', '世江东大族。少孤，为从祖康纲纪门户。年二十一，历东西曹令史，海昌屯田都尉，领县事。年旱，开仓济民，督农桑。讨会稽山越贼帅潘临、鄱阳尤突，所向皆服，拜定威校尉。权配逊策女，数访世务，逊议以 “平山寇叛，取精锐。”权纳其策。由虚势伏兵，破丹杨费栈，安内患，得精卒数万。建安二十四年，蒙称疾瞒关羽，逊代献骄兵计，军暗渡取荆州，除抚边华亭侯。败詹晏、屈陈凤。破房陵邓辅、南乡郭睦，诱降文布。迁镇西将军，封娄侯。陆逊论治荆州“拔人才、未亲疏。”权纳之。黄武元年，拜大都督、假节。督军五万西陵拒刘，伐谋分兵相机而动。火攻，备军尽殁；伏兵，逊逸待劳。加拜辅国将军，领荆州牧，改封江陵侯。吴蜀合，捆以外逊主之，权留玺于逊自裁度。皖县破曹休，缴获从辎重。黄龙元年，拜上大将军、右都护。辅太子。京外上疏：“宽刑罚、忘过记功，以成王业。阻权偏师取夷州。”公孙渊背盟，权欲征，逊陈弊利“志行万里者，不中道辍；图四海，匪怀细害大。乞息六师，定中夏。”权纳焉。嘉禾五年，逊协诸葛瑾攻襄阳。信韩扁为敌虏。逊佯攻暗退兵，袭江夏附者众。陷魏江夏太守逯式解边害。嘉禾六年，平吴遽乱，定三郡。逊忧吕壹弄权，陈曲直于权。年少丰，开仓济民。逊善赌人，昔言以诸葛恪、暨艳、杨竺终败丧，果应。赤乌七年，代顾雍为丞相。陈 “太子正统，藩正有别，当彼此得所，上下获安。”叩头流血。权不纳，又累遣使责逊，逊愤恚卒，年六十三。孙休时，谥昭侯。', '/api/uploads/images/20260301/cc7056aed5f94cddabe1abf0dd47e214.png', 89, '2026-03-01 10:44:17', '2026-05-06 10:15:52');
INSERT INTO `person` VALUES (13, '吕蒙', '字子明', '吴国', '少年时依附姊夫邓当，随孙策为将。以胆气称，累封别部司马。孙权统事后，渐受重用，从破黄祖作先登，封横野中郎将。从围曹仁于南郡，并于濡须数御曹军，屡献奇计，累功拜庐江太守。在军旅之时，亦发愤读书，深为孙权、鲁肃所倚赖。后进占荆南三郡，计擒郝普，于合淝战奋勇抵抗魏军追袭，以功除左护军、虎威将军。又后上代鲁肃守陆口，设计袭取荆州，击败蜀汉名将关羽，拜南郡太守，封孱陵侯，受勋殊隆。然而旋即得病，不治而薨，享年四十二岁。', '/api/uploads/images/20260301/b40fd5d252d546508b58a9070bf10705.png', 88, '2026-03-01 10:44:17', '2026-05-06 10:15:33');
INSERT INTO `person` VALUES (14, '司马懿', '字仲达', '魏国', '世家豪族出身，早年在郡中作小吏，后被曹操辟为文学掾。曹操称魏王后，司马懿为太子中庶子，佐助曹丕，与陈群等同列“四友”，是曹丕智囊团的主要人物。襄樊之战时和蒋济劝曹操勿迁都，可割南封孙权，令其袭杀关羽，事后如他所料。曹丕代汉后，司马懿节节高升，开始掌握重权。曹叡继位后，司马懿坐镇宛城，督荆、豫二州军事，主持荆州对吴攻战，后接替曹真总管对蜀汉的防御任务，数次成功防御诸葛亮北伐。在淮南和上邽的屯田成效显著，为魏军屯的创办人。后出兵平公孙渊。曹芳继位后，司马懿、曹爽共同辅政。司马懿受曹爽排挤，后发动高平陵之变诛杀曹爽一族，自此掌握魏国大权。司马懿病逝后，魏国政权仍由其儿子把持，多年后导致晋朝代魏的发生。司马懿被后代追封为晋朝皇帝。', '/api/uploads/images/20260301/f7a2bde0555243c39780b23d5f77f8f1.png', 87, '2026-03-01 10:44:17', '2026-05-06 10:14:45');
INSERT INTO `person` VALUES (15, '司马昭', '字子上', '魏国', '　司马懿次子。昭随父抗蜀，多有军识。景初二年，封新城乡侯。正始初，迁洛阳典农中郎将。曹髦时，继兄司马师为大将军。专揽国政，阴谋代魏。甘露五年，杀魏帝曹髦，另立曹奂为帝。景元四年，分兵谴钟会、邓艾、诸葛绪三路伐蜀，灭之。自称晋公。后加晋王。咸熙二年，薨。昭死数月，子司马炎代魏称帝。建晋朝。追尊昭为文帝，庙号太祖。', '/api/uploads/images/20260301/0e965942cb43468bbdf8eb41a92898c8.png', 86, '2026-03-01 10:44:17', '2026-05-06 10:15:02');
INSERT INTO `person` VALUES (16, '曹丕', '字子桓', '魏国', '自幼善骑射，好击剑，常从曹操征战。东汉献帝建安年间为五官中郎将、副丞相，留守邺城。后立为魏国太子，常从诸生宴游为乐。曹操去世后，曹丕继位为丞相、魏王，不久代汉称帝，在位七年去世。政绩有陈群制九品官人法、恢复太学、限制宦官和妇人从政。曹丕喜好文学，八岁能着文，有异才，是建安文学的代表人物之一，首开中国文学批评史的先河。有集二十三卷、《典论》五卷、《列异志》三卷，今多散失，其中《典论》为我国最早的文学理论专著。明人编有《魏文帝集》，与曹操集、曹植集合称《三曹集》。', '/api/uploads/images/20260301/733c79587baa46109f636649cad6a189.png', 85, '2026-03-01 10:44:17', '2026-05-06 10:14:29');
INSERT INTO `person` VALUES (17, '曹植', '字子建', '魏国', '曹操之子。三国时杰出文学家。曹植很有才学，早年被曹操宠爱，几乎被立为太子，后失宠。魏文帝时，他受兄长曹丕的猜忌和迫害，屡遭贬爵和改换封地。魏明帝时，曹植多次上书，希望能够得到任用，但终未能如愿，忧郁而死，年仅四十一岁。曹植为建安文学中成就最高者，其诗以笔力雄健和词采画眉见长，留有集三十卷，已佚，今存《曹子建集》为宋人所编。', '/api/uploads/images/20260301/aa9a83bf80b7405b846363ea9931e66b.png', 84, '2026-03-01 10:44:17', '2026-05-06 10:14:10');
INSERT INTO `person` VALUES (18, '荀彧', '字文若', '魏国', '从小就被人认为有王佐之才，董卓入京后辞官回乡带领族人迁到冀州。荀彧认为袁绍终不能成大事，便去东郡投靠曹操，曹操非常欣赏他，把他比作张良并任他为司马，那年荀彧二十九岁。曹操攻打陶谦时吕布袭取了兖州，荀彧临危不惧单身前往说退豫州刺史郭贡的数万人马，并与程昱保住了三座城池。不久吕布败走，荀彧又劝说曹操迎接汉献帝，因此被升为侍中、尚书令。因为荀彧多次推荐优秀人才给曹操如戏志才、郭嘉等，所以曹操更加敬重荀彧，每有大事都先与他商议。袁绍势力强大，曹操对是否与他开战而犹豫不决，荀彧就用四胜四败之说开导曹操，使他终下决心抗袁。官渡之战时回信坚定了曹操的意志，最后得已击败袁绍统一中原，这都是荀彧的计划。建安十七年董昭等人劝曹操即公位，荀彧私下表示反对，因此遭到曹操的忌恨，并在征讨孙权时带他出征，因为以往曹操出兵荀彧都是留守后方，因此荀彧又愁又怕，终于在寿春病亡，死后被追谥为敬侯，后又被追赠太尉。', '/api/uploads/images/20260301/ea45bfbccadf422aab0c0eb7793799d4.png', 83, '2026-03-01 10:44:17', '2026-05-06 10:13:54');
INSERT INTO `person` VALUES (19, '郭嘉', '字奉孝', '魏国', '曹操之司空军祭酒。郭嘉少年时就有卓识远见，隐居乡间只与众多英豪为伍。早期曾经投靠过袁绍，但看到袁绍无果断的抉择力和任用察识贤能的才能，成不了大事便离开袁绍。后来由于曹操的谋士戏志才的死，郭嘉受曹操谋士荀彧的举荐，和曹操详谈后互相肯定对方的能力。袁绍曾经送信羞辱曹操，郭嘉提出十胜十败论，对比曹操和绍的优胜劣败，鼓舞了曹操；又分析时局，认为先扫平吕布，再谋取天下。曹操东征吕布，久攻下邳不下，便有意退兵，但郭嘉与荀攸都认为吕布强攻下必败，决沂、泗水灌城，终破城。郭嘉认为不该让因吕布逆袭下投靠的刘备邀击袁术，认为这是放虎归山，后来刘备果然杀曹操置的徐州刺史车冑而叛。曹操想趁刘备立足未稳时速破，但诸将忧虑袁绍出兵，郭嘉指出袁绍反应迟缓应不会有大规模用兵，支持曹操的决定，事情结果也如他所料。官渡对峙时，孙策有袭击许昌之意，但是郭嘉分析认定孙策必为小人所害，稳定了曹操的信心。袁绍死后，建议曹操暂时退兵，让袁绍二子相残，后袁谭来投，曹军再次进击攻下袁尚的邺城。在南皮杀掉复叛的袁谭后，劝曹操多用河北贤才。追袭袁熙、袁尚余党时劝曹操兵贵神速，直指受袁氏之恩的乌丸大本营柳城，终破三郡乌丸並让他们臣服。可惜因水土不服，气候恶劣，日夜急行操劳过度而病死。曹操深感痛惜，泪流满面，对手下众人说：“大家跟我差不多年岁，只有郭嘉最年轻，本来想托嘱后事，但是却中年而丧，令人叹息。”赤壁战败后更慨叹：“若奉孝在，不使孤至此！”', '/api/uploads/images/20260301/4d82c790b4034a0b97c0513809405d37.png', 82, '2026-03-01 10:44:17', '2026-05-06 10:13:31');
INSERT INTO `person` VALUES (20, '贾诩', '字文和', '魏国', '著名谋士。先从董卓，后又成为张绣的谋士。张绣曾用他的计策二败了曹操，官渡之战前他劝张绣归降曹操。曹操在官渡战袁绍、潼关破西凉马超、韩遂，都用他的奇计。曹操占荆州想乘机顺江东下为贾诩劝阻，说应该安抚百姓等待时机，曹操不从，结果在赤壁之战中大败而归。在曹操立继位人问题上贾诩暗助了曹丕。曹丕日后称帝封其官为太尉、魏寿亭侯。曹丕问应先灭蜀还是吴，贾诩建议应先治理好国家再动武，曹丕不听，果然征吴无功而反。贾诩认为自己非曹操旧臣，却策谋深长，所以怕曹操猜嫌，于是采取自保策略，闭门自守，不与别人私下交往，他的子女婚嫁也不攀结权贵。死时七十七岁。', '/api/uploads/images/20260301/14c38ae1295f447d87b711c78a078d9f.png', 81, '2026-03-01 10:44:17', '2026-05-06 10:13:11');
INSERT INTO `person` VALUES (21, '许褚', '字仲康', '魏国', '与葛陂贼交战时在箭矢耗尽的情况下掷石攻敌，后在粮食短缺的情况下诈作与贼和解并以耕牛交换粮食一但在牛突然狂奔的情况下拿着牛反方向行百余步，由此在淮汝一带的人提起许褚之名皆畏惮。曹操复屯官渡时发现欲谋害曹操者，更全部杀掉。关中之战时左手拿马鞍，右手控船令曹操安然成功渡河，所以与马韩会面时只让许褚相随，期间马超欲袭曹操，但听闻许褚之名兼怀疑从骑就是许褚，便问曹操虎侯安在，曹操指着许褚;许褚怒视马超以令他放弃，自此天下皆以此称呼许褚。当曹操去世时许褚哭至吐血，曹丕迁作武卫将军，负责宫中安全。曹叡继位时封其为牟乡侯，谥曰壮侯。', '/api/uploads/images/20260301/7b1f46118862425e8a8e3ade0587b0ca.png', 80, '2026-03-01 10:44:17', '2026-05-06 10:12:36');
INSERT INTO `person` VALUES (22, '张辽', '字文远', '魏国', '以武力过人被召为从事。先后从属丁原、董卓、吕布，及至吕布败后才归于曹操。从曹操以后，辽随军征讨，多有战功，与关羽解白马之围，围降昌豨于东海，攻袁尚于邺城，斩乌丸单于蹋顿于白狼山，又讨平梅成、陈兰贼寇。赤壁战后，曹操留张辽、乐进、李典等守合肥，以御孙权。后孙权果引十万大军入寇，张辽率八百步兵冲阵让孙权军丧失士气，后孙权退兵，张辽观察后令军断桥，追击，差点活捉孙权。威震江东，江东儿啼不肯止者，其父母以辽名吓之。被曹操拜为征东将军。曹丕称帝仍令张辽守御孙权。张辽屯雍丘，却在此得病。但张辽不负众望，以抱病之躯击退吴将吕范。同年（黄初三年），张辽病逝于江都，谥曰刚侯。后人根据三国志记载“布为李傕所败，从布东奔徐州，领鲁相，时年二十八。”一句，多推测张辽生于169年，此说存疑，只能确定其生年范围为169-171年。', '/api/uploads/images/20260301/461f038be7b64332a46f15ab56291f0e.png', 79, '2026-03-01 10:44:17', '2026-05-06 10:12:17');
INSERT INTO `person` VALUES (23, '徐晃', '字公明', '魏国', '原为军阀杨奉的部下任骑都尉。曹操击败杨奉后投靠曹操。参加过多次重大作战，智勇双全，战功卓著，治军有方。曹操曾称赞徐晃：“徐将军可谓有周亚夫之风矣。”在曹操军中历任裨将军、偏将军、横野将军、平寇将军。官渡之战中烧毁袁绍的后勤粮草有功，加封都亭侯。曹丕称帝登基后官拜右将军，封建乡侯，后进封杨侯。击败刘封于上庸后，驻守阳平，改封阳平侯。徐晃一生谨慎，战前常派斥侯，先为不可胜。对曹氏集团忠心耿耿，曾说过：“古人患不遭明君，今幸遇之，当以功自效，何用私誉为！”太和元年病死，死后谥壮侯。', '/api/uploads/images/20260301/a24e3b8b5013492ea08c29629fbc3087.png', 78, '2026-03-01 10:44:17', '2026-05-06 10:11:52');
INSERT INTO `person` VALUES (24, '张郃', '字儁乂', '魏国', '征西车骑将军。先从韩馥，后投袁绍，在与公孙瓒的交战中多有功劳。官渡之战时，张郃受郭图陷害，率众投降于曹操，得以重用，随曹操平定北方，远征乌丸，平马超，斩宋建，灭张鲁，多有战功。后来，张郃随夏侯渊驻守汉中，在夏侯渊被杀后暂代主帅，维持败兵。魏明帝时诸葛亮第一次北伐，张郃奉命救援陇右，在街亭大败蜀将马谡，导致诸葛亮撤兵；诸葛亮第四次时，张郃随司马懿前往相拒。后诸葛亮粮尽退兵，张郃追至木门，与诸葛亮军交战，被飞矢射中右膝而亡。', '/api/uploads/images/20260301/172de3176d9d4c1d9c241016ad383c58.png', 77, '2026-03-01 10:44:17', '2026-05-06 10:11:30');
INSERT INTO `person` VALUES (25, '于禁', '字文则', '魏国', '最早随鲍信起兵，鲍信死后归附曹操，被任为官军司马。从此跟随曹操四处征战。曹操兵败宛城，曹军的青州兵四处抢劫，被于禁追杀后就去告发于禁叛变，恰好此时张绣追兵来攻，于禁就先扎下营寨才去见曹操，曹操问他怎么不先来解释，于禁认为分辩事小，退敌事大，曹操因此十分高兴，于是封他为益寿亭侯。后来败吕布，破袁绍，于禁与其它五良将都轮流任先锋官而表现活跃。还有一次曹操厌恶朱灵并想撤掉他的兵权，就派于禁去办，于禁手执文书仅带数十骑就出色地完成了任务，他就是这样地令人畏惧，被迁至左将军，假节钺。关羽包围曹仁于樊城，于禁去救援，但遇上汉水暴涨为关羽乘船进攻，于禁投降了敌人，而他手下的庞德却不屈被杀。后来关羽被孙权所破，于禁也就归属了吴国，直到黄初二年才被送回魏国，那时他都已经须发皆白，面容憔悴，泪流满面。曹丕就命他去拜见高陵（曹操的陵墓），因为陵中画有他屈膝降敌，庞德不屈的图画，所以于禁不久就羞愧发病而死，死后追谥为厉侯。', '/api/uploads/images/20260301/4c8e4dafb1b84dceab3bbdf6c5f3bf64.png', 76, '2026-03-01 10:44:17', '2026-05-06 10:11:07');
INSERT INTO `person` VALUES (26, '乐进', '字文谦', '魏国', '初为帐下吏，迁陷阵都尉。后历大小百余战，每战皆捷，因军功累迁讨寇校尉、遊击将军、折冲将军、右将军，封广昌亭侯。以胆识英烈而从曹操，随军多年，南征北讨，战功无数，从击袁绍于官渡，奋勇力战，斩袁绍部将淳于琼。又从击袁绍子谭、尚于黎阳，斩其大将严敬。乐进与张辽、于禁、张合、徐晃号为名将。不久乐进别击黄巾、雍奴、管承，皆大破之。从平荆州，留屯襄阳，进击关羽、苏非等人，击退其众，南郡诸郡的山谷蛮夷都前往乐进处投降。后来从曹操征孙权，假进节。曹操回师后，留乐进与张辽、李典屯于合肥。又以乐进数有军功，迁右将军。建安二十三年逝世，谥曰威侯。', '/api/uploads/images/20260301/e6beab0fc06a4a3287d7db567763dad1.png', 75, '2026-03-01 10:44:17', '2026-05-06 10:10:48');
INSERT INTO `person` VALUES (27, '姜维', '字伯约', '蜀国', '幼年丧父和母亲生活，喜爱郑玄的经学，曾为魏中郎将，参天水郡军事。诸葛亮第一次北伐后投蜀汉，因他忠勤时事、思虑精密、敏于军事、即有胆义，又兼心存汉室，故深得诸葛亮的器重。诸葛亮于五丈原病逝后，姜维令杨仪反旗鸣鼓，导致尾追的司马懿退兵。姜维继诸葛亮之略，伺图中原，恢复汉室。又因其熟悉西方风俗，欲以羌胡为羽翼断陇西为蜀汉所有。蒋琬和费祎在位时实行保境安民，姜维每次出兵不过万人，但费祎被刺杀后能实行自己的志向，于是伺机累次兵伐中原，降李简、斩徐质、大破王经，一时挫魏国之威。但也有麹城被夺、段谷及侯和之败。后请刘禅杀专权的宦人黄皓不果，以屯田之名避禍沓中。司马昭大举伐蜀姜维上表请朝廷增援，但黄皓并不理会。姜维为邓艾军所缠，后用计令诸葛绪误以他将袭雍州而得脫，于剑阁拒守钟会十余万大军。奈先有江由守将马邈投降，再有诸葛瞻不听黄崇抢占涪，更战死于绵竹，蜀汉震恐后从投降派谯周之议，后主投降，并敕令姜维也降，将士得知后奋怒斩石。姜维乃佯降于钟会，看出他阴有异志策应他造反，图谋杀会后重扶汉室，乃事败，姜维及妻子皆伏诛。', '/api/uploads/images/20260301/06e357eef8f2408ba396640c5ef40495.png', 74, '2026-03-01 10:44:17', '2026-05-06 10:10:28');
INSERT INTO `person` VALUES (28, '费祎', '字文伟', '蜀国', '性格宽和，少时从伯父入蜀游学，留于益土，及刘备平定益州，费祎便留蜀为官。后主刘禅即位后，费祎任黄门侍郎，深得丞相诸葛亮所器重。后来费祎迁昭信校尉，出使东吴，孙权、诸葛恪、羊茞等人以辞锋论难，而费祎据理以答，辞义兼至，始终不为所屈。孙权甚异其才，自礼遇之，费祎也因常使吴。北伐时为中护军，又转为司马。当时军师魏延与长史杨仪不和，坐常争论，费祎常为二人谏喻，两相匡护，以尽其用。诸葛亮死后，费祎为后军师。不久又代蒋琬为尚书令，再迁大将军。当国以来，尽心抚政，多御敌寇；性格谦素甚廉，家无余财。延熙十六年，费祎于宴会上为魏降将郭循行刺身死，追谥敬侯。', '/api/uploads/images/20260301/1e864b304ada4f25bab20dfc36bbfd85.png', 73, '2026-03-01 10:44:17', '2026-05-06 10:10:08');
INSERT INTO `person` VALUES (29, '蒋琬', '字公琰', '蜀国', '蜀汉大臣。随刘备入川，因其政以安民为本，不加修饰，所以被免官。后被重新起用，得代张裔为长史。蒋琬很得诸葛亮的赏识，诸葛亮曾向刘禅说：“臣若不幸，后事宜以付琬。”诸葛亮去世后，蒋琬以出类拔萃、神色自若使得众望所归，任尚书令一职，正式成为诸葛亮的继承者。不久升职为大司马。蒋琬谦恭厚道，品性高洁，为人所崇。\n蒋琬在战略上大胆改革，以“防守反攻”代替“以攻为守”来进行战略布局，闭关息民，蜀汉的国力有了很大的增强。后琬又以大将军的身分屯驻汉中，并对诸葛亮的北伐策略作了认真研究，他以为：“昔日诸葛亮数窥秦川，道险运艰，竞不能克，不若乘水东下。乃多作舟船，欲由汉、沔袭魏兴、上庸。”并且上疏刘禅，提出了“东西并力”、“涪为本营”、“姜维驻凉”三条良策。然而，天妒英才，正当蒋琬要一展鸿图的时候，不幸得急病辞世。', '/api/uploads/images/20260301/ddfec151251f4fb8ae8b5b20b2738d1c.png', 72, '2026-03-01 10:44:17', '2026-05-06 10:09:47');
INSERT INTO `person` VALUES (30, '庞统', '字士元', '蜀国', '刘备之军师中郎将。少时朴钝，未有识者，唯颍川司马徽异之。后郡命为功曹，属周瑜。性好人伦，勤於长养。吴将周瑜卒，统送丧至吴。先主领荆州，统以从事守耒阳令，在县不治，免官。鲁肃、诸葛亮皆荐之，先主见与善谭，大器之，以为治中从事。亲待亚於诸葛亮，遂与亮并为军师中郎将。亮留镇荆州。统随从入蜀。益州牧刘璋与先主会涪，统进策除之，先主不从。璋既还成都，先主当为璋北征汉中，统复说三计。先主然其中计，即斩怀、沛，还向成都，所过辄克。进围雒县，统率众攻城，为流矢所中，卒，时年三十六。先主痛惜，言则流涕。拜统父议郎，迁谏议大夫，诸葛亮亲为之拜。追赐统爵关内侯，谥曰靖侯。', '/api/uploads/images/20260301/2e22bcc732b347988652e089a82039a8.png', 71, '2026-03-01 10:44:17', '2026-05-06 10:09:28');
INSERT INTO `person` VALUES (31, '法正', '字孝直', '蜀国', '　早年投靠刘璋，但既不受重用，又受同事诽谤。在出使拜访过刘备后，暗中与张松策划拥戴刘备，并利用再次出使刘备的机会，私下向刘备提出借机取蜀的计划。并在刘备征蜀过程中准确预测了刘璋不会采用郑度之计。建安十九年刘备成功取蜀，法正被赐予高位，地位仅次于诸葛亮。建安二十二年，法正分析形势，鼓动刘备进攻汉中，并建奇策斩杀夏侯渊。刘备自立为汉中王后，法正被任命为汉中国尚书令、护军将军。法正的奇谋妙策，诸葛亮也为之惊奇。', '/api/uploads/images/20260301/2befb9b5c51e4e2ea233de9a8588b271.png', 70, '2026-03-01 10:44:17', '2026-05-06 10:09:09');
INSERT INTO `person` VALUES (32, '马谡', '字幼常', '蜀国', '越隽太守、参军。兄弟五人，并有才名。兄良，侍中。谡以荆州从事随先主入蜀，除绵竹成都令、越隽太守。才器过人，好论军计，丞相诸葛亮深加器异。先主临薨谓亮曰：“马谡言过其实，不可大用，君其察之！”亮犹谓不然，以谡为参军，每引见谈论，自昼达夜。建兴三年，亮征南中，谡定攻心之计，亮深然之。建兴六年，亮出军向祁山，时有宿将魏延、吴懿等，论者皆言以为宜令为先锋，而亮违众拔谡，统大众在前，与魏将张郃战于街亭，为郃所破，士卒离散。亮进无所据，退军还汉中。谡下狱物故，亮为之流涕，谡年三十九。十万之众为之垂涕。亮自临祭，待其遗孤若平生。', '/api/uploads/images/20260301/e52b00f28d3f40cc8d92979caeab0f57.png', 69, '2026-03-01 10:44:17', '2026-05-06 10:08:28');
INSERT INTO `person` VALUES (33, '黄月英', NULL, '蜀国', '为沔阳名士黄承彦之女，黄承彦以黄月英有才干向诸葛亮推荐，请求配婚，诸葛亮答应后遂与黄月英结为夫妻，相传黄月英黄头发黑皮肤，但知识广博。但也有一说指黄月英本人极美，因此遭到乡里其他年轻女性的嫉妒而诋毁她的容貌。 诸葛亮发明木牛流马，相传就是从黄月英的传授的技巧上发展出来。荆州一带的特产，相传部分也由黄月英所制造或发明。现今襄樊一带，还可以听到很多关于诸葛亮与黄月英的动人传说。黄月英是民间传说中的名字，由于使用广泛，因此本辞典采用其名。', '/api/uploads/images/20260301/559e52734b0648f2aae07214c4c0dfdb.png', 68, '2026-03-01 10:44:17', '2026-05-06 10:07:57');
INSERT INTO `person` VALUES (34, '孙策', '字伯符', '吴国', '汉讨逆将军、会稽太守。长沙太守坚长子，坚初兴义兵，策将母徙居舒，与周瑜相友，收合士大夫，江、淮间人咸向之。坚薨，还葬曲阿。已乃渡江居江都。徐州牧陶谦深忌策。策舅吴景，时为丹杨太守，策乃载母徙曲阿，与吕范、孙河俱就景，因缘召募得数百人。兴平元年，从袁术。术甚奇之，以坚部曲还策。太傅马日磾杖节安集关东，在寿春以礼辟策，表拜怀义校尉。术初许策为九江太守，已而更用丹杨陈纪。后术欲攻徐州，从庐江太守陆康求米三万斛。康不与，术大怒。策昔曾诣康，康不见，使主簿接之。策尝衔恨。术遣策攻康，拔之，术复用其故吏刘勋为太守，策益失望。先是，刘繇为扬州刺史，州旧治寿春。寿春，术已据之，繇乃渡江治曲阿，与术相攻。策乃说术，乞助景等平定江东。术表策为折冲校尉，行殄寇将军，兵财千余，骑数十匹，宾客原从者数百人。策母先自曲阿徙于历阳，策又徙母阜陵，渡江转斗，所向皆破，莫敢当其锋，而军令整肃，百姓怀之。又破严白虎等。时袁术僭号，策以书责而绝之。曹公表策为讨逆将军，封为吴侯。是时哀绍方强，而策并江东，曹公力未能逞，且欲抚之。建安五年，曹公与袁绍相拒于官渡，策阴欲袭许，迎汉帝，密治兵，部署诸将。未发，会为故吴郡太守许贡客所杀。先是，策杀贡，贡小子与客亡匿江边。策单骑出，卒与客遇，客击伤策。创甚，请张昭等嘱以后事，呼权佩以印绶，至夜卒，时年二十六。权称尊号，追谥策曰长沙桓王。', '/api/uploads/images/20260301/ba41d935d0ad4c0abc29480386f72d15.png', 67, '2026-03-01 10:44:17', '2026-05-06 10:07:40');
INSERT INTO `person` VALUES (35, '太史慈', '字子义', '吴国', '少好学，善弓马，仕郡奏曹史。会郡与州有隙，曲直未分，以先闻者为善。时州章已去，郡守恐后之，求可使者。慈年二十一，以选行，因坏章，由是知名，而为州家所疾，恐受其祸，乃避之辽东。北海相孔融闻而奇之，数遣人讯问其母，并致饷遗。时融以黄巾寇暴，出屯都昌，为贼管亥所围。慈乃突围求救于刘备，解围。扬州刺史刘繇与慈同郡，慈自辽东还，未与相见，暂渡江到曲阿见繇，未去，会孙策至。繇轻慈，不用之。时独与一骑卒遇策。策从骑十三，皆韩当、宋谦、黄盖辈也。慈便前斗，正与策对。策刺慈马，而揽得慈项上手戟，慈亦得策兜鍪。会两家兵骑并各来赴，于是解散。慈当与繇俱奔豫章，而遁于芜湖，亡入山中，称丹杨太守。策躬自攻讨，遂见囚执，以礼降。即署门下督，还吴授兵，拜折冲中郎将。后刘繇亡于豫章，士众万余人未有所附，策命慈往抚安焉。刘磐骁勇，数为寇于艾、西安诸县。策以慈为建昌都尉，治海昬，并督诸将拒磐。磐绝迹不复为寇。慈猿臂善射，曹公闻其名，遗慈书，以箧封之，发省无所道，而但贮当归。吴主权统事，以慈能制磐，遂委南方之事。年四十一，建安十一年卒。', '/api/uploads/images/20260301/b26bd7ec86e94a6eb094a60214edd2c4.png', 66, '2026-03-01 10:44:17', '2026-05-06 10:07:24');
INSERT INTO `person` VALUES (36, '甘宁', '字兴霸', '吴国', '吴折冲将军、西陵太守。少有气力，好游侠。曾聚合一伙轻薄少年成群结队，携弓带箭，头插鸟羽，身佩铃铛。当时百姓一听铃响便知是甘宁到了。时人以“锦帆贼”呼之。后读诸子，率八百健儿依刘表，因居南阳，不见进用。欲投江东但为黄祖留于夏口。期间曾射杀凌统之父凌操，因此与凌统有杀父之仇。但仍不获重用，得苏飞之助得入江东。为周瑜和吕蒙所荐得以获孙权接见，其对答令孙权赏析，受重用。后从攻曹仁于南郡，随镇益阳拒关羽，从攻皖城获朱光，于合肥奋战保孙权等战立功。濡须时更以百人袭曹营，事后孙权说：“孟德有张辽，孤有甘兴霸，足可敌矣。”仗义疏财，深得士卒拥戴。夷陵之战前病死，其军为潘璋所并。', '/api/uploads/images/20260301/8accbaddc9674699a1e13365779f354d.png', 65, '2026-03-01 10:44:17', '2026-05-06 10:07:07');
INSERT INTO `person` VALUES (37, '周泰', '字幼平', '吴国', '泰与蒋钦随孙策为左右，服事恭敬，数战有功。策入会稽，署别部司马，授兵。权爱其为人，请以自给。策讨六县山贼，权住宣城，使士自卫，不能千人，意尚忽略，不治围落，而山贼数千人卒至。权始得上马，而贼锋刃已交于左右，或斫中马鞍，众莫能自定。惟泰奋激，投身卫权，胆气倍人，左右由泰并能就战。贼既解散，身被十二创，良久乃苏。是日无泰，权几危殆。策深德之，补春谷长。后从攻皖，及讨江夏，还过豫章，复补宜春长，所在皆食其征赋。从讨黄祖有功。后与周瑜、程普拒曹公于赤壁，攻曹仁于南郡。荆州平定，将兵屯岑。曹公出濡须，泰复赴击，曹公退，留督濡须，拜平虏将军。后权破关羽，欲进图蜀，拜泰汉中太守、奋威将军，封陵阳侯。黄武中卒。', '/api/uploads/images/20260301/0c5f32104e1647ef97839fec1cdbd465.png', 64, '2026-03-01 10:44:17', '2026-05-06 10:06:49');
INSERT INTO `person` VALUES (38, '丁奉', '字承渊', '吴国', '晓勇而有计谋。他年轻时作小将，多次跟随其他将领征伐，经常勇冠三军。孙亮继位后，丁奉升为冠军将军，参加了吴魏龙兴之战，大破敌人先头部队，立下了大功，升为灭寇将军。孙休继位后，丁奉帮助孙休用计诛杀了权臣孙綝，升为大将军，加封左右都护。后来，孙休病逝，丁奉等人拥立孙皓为帝，被封为右大司马、左军师。几年后，丁奉去世，家人受谗言而被流放。', '/api/uploads/images/20260301/8a20bbeed4d6420aa01ced4f581aaa89.png', 63, '2026-03-01 10:44:17', '2026-05-06 10:06:31');
INSERT INTO `person` VALUES (39, '鲁肃', '字子敬', '吴国', '自幼丧父，与祖母一起居住，家富于财，喜好周济穷人结交朋友。早年，鲁肃在袁术手下当东城长，后经周瑜的推荐，成为孙权的参谋，很早就为孙权谋划了成就帝业的战略计划，深受孙权器重。赤壁战前，鲁肃在联合刘备、劝说孙权抗曹等方面都起了极为重要的作用，并在之后协助周瑜取得赤壁之战的胜利。赤壁战后，鲁肃从大局考虑，又劝说孙权将荆州借给刘备，继续巩固孙刘联盟。周瑜去世后，鲁肃接任他的位置，负责处理荆州事务。建安二十二年卒，时年四十六岁。', '/api/uploads/images/20260301/b00d407787ff4be3b54a9affc5aed0ca.png', 62, '2026-03-01 10:44:17', '2026-05-06 10:06:13');
INSERT INTO `person` VALUES (40, '张昭', '字子布', '吴国', '张昭（156年－236年），字子布。徐州彭城县（今江苏省徐州市）人。 汉末至三国时孙吴政权重臣。 东汉末年，张昭为避战乱而南渡至扬州。孙策创业时，任命其为长史、抚军中郎将，将文武之事都委任于张昭。孙策临终前，将其弟孙权托付给张昭，张昭率群僚辅立孙权，并安抚百姓、讨伐叛军，与周瑜等辅助孙权稳定局势。孙权每次出征，常留张昭镇守后方，领幕府事，并敬称他为“张公” 。赤壁之战时，张昭鉴于曹操势大，持主降论 ，从而被排挤出军政决策中心 。孙权代理车骑将军时，任命张昭为军师。孙权被封为吴王后，任绥远将军，封由拳侯。此后曾参与撰定朝仪。孙权两次要设立丞相时，众人都推举张昭，孙权以张昭敢于直谏、性格刚直为由而不用他，先后用孙邵、顾雍。黄龙元年（229年），孙权称帝，张昭以年老多病为由，上还官位及所统领部属，改拜辅吴将军、班亚三司，改封娄侯。晚年时一度不参与政事，在家著书，即使偶有参加朝议，也常与孙权产生激烈冲突 。嘉禾五年（236年），张昭去世，享年八十一岁，谥号“文“。', '/api/uploads/images/20260301/bc26a9f88dd3431d80134dd1647500ad.png', 61, '2026-03-01 10:44:17', '2026-05-06 10:05:51');
INSERT INTO `person` VALUES (41, '诸葛瑾', '字子瑜', '吴国', '诸葛亮之兄，经鲁肃推荐，为东吴效力。胸怀宽广，温厚诚信，得到孫权的深深信赖，努力缓和蜀汉与东吴的关系。吕蒙去世后，诸葛谨代吕蒙领南郡太守，驻守公安。孙权称帝后，诸葛谨官至大将军，领豫州牧。军国大政，多所咨谋，为主所重。赤乌四年（241）卒，年六十八，遗令薄葬。', '/api/uploads/images/20260301/f5e6c953b6cc4a1a9bc16a37c6017e96.png', 60, '2026-03-01 10:44:17', '2026-05-06 10:04:32');
INSERT INTO `person` VALUES (42, '曹仁', '字子孝', '魏国', '魏大司马。太祖从弟也，少好弓马弋猎。后豪杰并起，仁亦阴结少年，得千馀人，周旋淮、泗之间，遂从太祖为别部司马，行厉锋校尉。太祖之破袁术，仁所斩获颇多。从征徐州，仁常督骑，为军前锋。别攻陶谦将吕由，破之，还与大军合彭城，大破谦军。太祖征吕布，仁别攻句阳，拔之，生获布将刘何。太祖平黄巾，迎天子都许，仁数有功，拜广阳太守。太祖器其勇略，不使之郡，以议郎督骑。太祖军还，为张绣所追，仁率厉将士甚奋，太祖壮之，遂破绣。太祖与袁绍久相持於官渡，仁击绍将韩荀，大破之。献计破壶关，封都亭侯。从平荆州，以仁行征南将军，留屯江陵，拒吴将周瑜。瑜将数万众来攻，仁登募得三百人，遣部曲将牛金逆与挑战。金等垂没，仁被甲上马，将其麾下壮士数十骑救之。太祖益壮之，转封安平亭侯。太祖讨马超，以仁行安西将军，督诸将拒潼关，破超渭南。苏伯、田银反，以仁行骁骑将军，都督七军讨银等，破之。复以仁行征南将军，假节，屯樊，镇荆州。关羽攻樊，仁激厉将士，示以必死，羽退走。仁少时不脩行检，及长为将，严整奉法令，常置科於左右，案以从事。及曹丕即王位，拜仁车骑将军，都督荆、扬、益州诸军事，进封陈侯，追赐仁父炽谥曰陈穆侯。后召还屯宛。孙权遣将陈邵据襄阳，诏仁讨之。文帝遣使即拜仁大将军。又诏仁移屯临颍，迁大司马，复督诸军据乌江，还屯合肥。黄初四年薨，谥曰忠侯。', '/api/uploads/images/20260301/9c8c65a4420e48139401473880b81fe8.png', 59, '2026-03-01 10:44:17', '2026-05-06 10:04:12');
INSERT INTO `person` VALUES (43, '曹洪', '字子廉', '魏国', '骠骑将军、特进。太祖从弟也，洪伯父鼎为尚书令，任洪为蕲春长。太祖起义兵讨董卓，至荥阳，为卓将徐荣所败。太祖失马，贼追甚急，洪下，以马授太祖，太祖辞让，洪曰：“天下可无洪，不可无君。”遂步从到汴水，水深不得渡，洪循水得船，与太祖俱济，还奔谯。太祖征徐州，时大饥荒，洪将兵在前，先据东平、范，聚粮谷以继军。以前后功拜鹰扬校尉，迁扬武中郎将。天子都许，拜洪谏议大夫。别征刘表，破表别将於舞阳、阴叶、堵阳、博望，有功，迁厉锋将军，封国明亭侯。累从征伐，拜都护将军。文帝即位，为卫将军，迁骠骑将军，进封野王侯，益邑千户，并前二千一百户，位特进；后徙封都阳侯。始，洪家富而性吝啬，文帝少时假求不称，常恨之，遂以舍客犯法，下狱当死。群臣并救莫能得。卞太后谓郭后曰：“令曹洪今日死，吾明日敕帝废后矣。”於是泣涕屡请，乃得免官削爵土。明帝即位，拜后将军，更封乐城侯，邑千户，位特进，复拜骠骑将军。太和六年薨，谥曰恭侯。子馥嗣。', '/api/uploads/images/20260301/359006eed2a54b28baebc079ac3316fa.png', 58, '2026-03-01 10:44:17', '2026-05-06 10:03:53');
INSERT INTO `person` VALUES (44, '夏侯惇', '字元让', '魏国', '西汉名臣夏侯婴之后。十四岁时，有人侮辱了他的老师，夏侯惇就杀了那个人，因此以性格刚烈有勇气而出名。曹操在陈留起兵，夏侯惇担任裨将，跟随征伐。后曹操征陶谦留惇守濮阳，期间陈宫反迎吕布来袭。曹操从徐州归还，从征吕布时被流矢射中左眼。当时大旱，蝗虫四起，夏侯惇于是截断太寿水修建陂，亲自搬运泥土，鼓励将士种田，为曹魏军屯之邹型。曹操迎献帝后以夏侯惇为河南尹。官渡之战时夏侯惇防守敖仓，掩护大军左侧安全。曹操破邺城后迁夏侯惇为伏波将军。从征孙权，曹操班师，留夏侯惇统曹仁、张辽等二十六军留守居巢。曹操经常邀请夏侯惇一起乘车外出，显得格外亲近，并允许他自由出入自己的卧室，别的将领都得不到这种待遇。后来，夏侯惇被升为前将军。曹丕即位后拜为大将军，后个月后去世。', '/api/uploads/images/20260301/9793d14638c14c279d80d03fcd7446ce.png', 57, '2026-03-01 10:44:17', '2026-05-06 10:03:37');
INSERT INTO `person` VALUES (45, '夏侯渊', '字妙才', '魏国', '夏侯婴之后、大将军惇族弟。自曹操陈留起兵起，便跟随征伐，历任陈留、颍川太守。官渡之战后，夏侯渊负责粮草补给，保证了曹操平定北方。而后夏侯渊又率兵四处征讨叛乱，破昌豨、徐和、雷绪、商曜等，战功卓著，又随曹操破马超等关中军、降杨秋、灭张鲁，曹操回邺时留夏侯渊驻长安，又破刘雄、梁兴、捲土重来的马超、韩遂、宋建等，再立奇功。而后夏侯渊督张郃、徐晃等留守汉中，与前来取汉中的刘备大军交战，为刘备将黄忠所袭，不幸战死。谥曰愍侯。魏齐王正始四年从祀曹操庙庭。', '/api/uploads/images/20260301/7e18086259ee4fa898fd906e968a3135.png', 56, '2026-03-01 10:44:17', '2026-05-06 10:03:17');
INSERT INTO `person` VALUES (46, '典韦', NULL, '魏国', '武猛校尉。擅使大双戟，膂力过人。为人壮猛任侠，曾为乡人刘氏报雠，杀人出市，追者数百人也莫敢近，由是为豪杰所识。初属张邈，属司马赵宠。军中的牙门旗既长且大，人们都不能把它举起，而典韦竟以一手便将其执而竖起。后属夏侯惇，曹操讨吕布于濮阳时，典韦奋力勇战，手持十余戟，大呼起，所抵无不应手倒者。为曹操所异，又因其人忠诚谨重，自此引典韦为近侍，迁为都尉，置之于左右。后曹操于宛城时，张绣先降而复反，急迫曹操本营；典韦守着大门，殊死恶斗，杀敌甚众，最终因敌人太多而战死。 ', '/api/uploads/images/20260301/51beb75384f3432b86ee1329d0030189.png', 55, '2026-03-01 10:44:17', '2026-05-06 10:02:56');
INSERT INTO `person` VALUES (47, '庞德', '字令明', '魏国', '年少为郡吏州从事，后从马腾讨羌氐有功，迁至校尉。袁谭遣郭援、高干等略取河东，曹操使钟繇率关中诸将讨之，庞德随马腾子超参战，且亲斩敌主帅郭援之首。因此被拜中郎将，封都亭侯。每有战斗时庞德常陷陈卻敌，勇冠腾军。后来马腾徵为卫尉入京，庞德留属马超。关中之战曹操破马超后庞德随马超逃亡。卷土重来的马超又为杨阜和夏侯渊所败后，随马超投靠汉中的张鲁。曹操定汉中，庞德随众降。曹操素闻其骁勇，拜立义将军，封关门亭侯，邑三百户。庞德与曹仁攻下宛，斩叛将侯音等后，南屯樊拒关羽。后亲自与关羽交战，射中关羽额头。当时庞德常乘白马，关羽军谓之白马将军，皆惮之。曹仁使庞德屯樊北十里，正好遇上豪雨十馀日，汉水暴溢，庞德与诸将避水上堤。为关羽乘船进攻，庞德被甲持弓，箭不虚发，自平旦力战至日中，箭尽与关羽军白刃，但最终庞德还是与少数部下乘小船欲突围至曹仁营。不过船覆沉而丟失弓矢，但仍然抱船，可惜终为关羽军所擒，立而不跪。关羽劝庞德投降，只换来庞德怒骂，遂为关羽所杀。曹操闻而悲之，为之流涕。曹丕即魏王位后，谥曰壮侯。', '/api/uploads/images/20260301/ef5bf2cb4ecc46088d2eda21bd1c5608.png', 54, '2026-03-01 10:44:17', '2026-05-06 09:51:02');
INSERT INTO `person` VALUES (48, '邓艾', '字士载', '魏国', '年少时就已是孤儿，曹操破荆州被徙至汝南，后随母至颍川襄城，读陈寔碑文后改名范，字士则。因宗族有相同者，故改为艾。因口吃被改为稻田守丛草吏。每当他看到高山大泽，总是规划指点哪里可以设置军营。为典农功曹时向中央汇报时因见司马懿，得到赏识被辟为太尉府掾，迁尚书郎。后著《济河论》陈述淮南屯田的方案，实施后军粮大增。又与郭淮拒姜维于洮阳有功，赐爵关内侯，加讨寇将军。司马师新辅政，多纳其计谋，乃分南匈奴为两部削弱其势。改任汝南太守时政绩卓著。后迁兗州刺史，于讨伐毋丘俭之役有功，进封方城乡侯。从陈泰解王经之围于狄道有功，升为安西将军，假节、领护东羌校尉。拒姜维于长城后迁征西将军。又破姜维于侯和，姜维退保沓中。司马昭大举伐蜀，邓艾险渡阴平，降江由，败诸葛瞻后，刘禅投降。以邓艾为太尉，增邑二万户，封子二人亭侯，各食邑干户。但其后邓艾的所作所为让司马昭疑虑，加上钟会等上表邓艾有叛乱的跡象，被槛车收押。钟会之乱时，邓艾和儿子忠为田续所杀。后得段灼上表为其平反。', '/api/uploads/images/20260301/d34a163724a5427890a9343fda31cfc1.png', 53, '2026-03-01 10:44:17', '2026-05-06 09:50:31');
INSERT INTO `person` VALUES (49, '钟会', '字士季', '魏国', '自幼才华横溢，上至皇帝、下至群臣都对他非常赏识。在征讨毌丘俭、诸葛诞其间，钟会屡出奇谋。被人比作西汉谋士张良，又曾为司马昭献策阻止了曹髦的夺权企图，钟会得以成为司马氏的亲信。景元年间，钟会独力支持司马昭的伐蜀计划，从而发动伐蜀之战。灭蜀后，钟会大力结交西蜀名士，打击邓艾等人，打算自立政权，但由于手下官兵不支持钟会的行动而发动兵变，钟会与姜维等人皆死于兵乱之中。', '/api/uploads/images/20260301/5ef87df5f87146228fac3abec0b92905.png', 52, '2026-03-01 10:44:17', '2026-05-06 09:50:12');
INSERT INTO `person` VALUES (50, '羊祜', '字叔子', '西晋', '蔡邕外孙，司马师的妻弟。西晋开国元勋，博学能文，清廉正直，娶夏侯霸之女为妻。曾拒绝曹爽和司马昭的多次征辟，后为朝廷公车征拜。司马昭建五等爵制时以功封为钜平子，与荀勖一起共掌机密。晋代魏后司马炎有吞吴之心，乃命羊祜坐镇襄阳都督荆州诸军事。在之后的十年里，羊祜屯田兴学，以德怀柔，深得军民之心；一方面又缮甲训卒，广为戎备，做好了伐吴的军事和物质准备，并在吴将陆抗去世后上表奏请伐吴，却遭到了众大臣的反对。咸宁四年，羊祜抱病回洛阳，同年十一月病故，并在临终前举荐杜预自代。', '/api/uploads/images/20260301/370cc3a451bc454b92beddad7a01eeed.png', 51, '2026-03-01 10:44:17', '2026-05-06 09:49:53');
INSERT INTO `person` VALUES (51, '杜预', '字元凯', '西晋', '出身在忠于曹魏政权的官宦世家，从小博学多通，但由于司马氏的专政和排挤使杜预受到牵连，年过三十仍未出仕。司马昭执政后杜预渐受重用，先后参与了伐蜀和《晋律》的修订。晋代魏后，杜预多次被晋武帝启用出镇边关，在任期间杜预提出了五十多项安边兴国的建议，均为朝廷采纳，并积极进行科学发明，修订出通行于世的历法。咸宁四年杜预继任羊祜为镇南大将军都督荆州事，期间兴修水利，奇袭西陵，三陈平吴。在最后的灭吴战争中担任西线指挥，智取江陵，招降交、广，为西晋的统一作出了卓越的贡献。', '/api/uploads/images/20260301/7021b0015815455290180ec18bd61875.png', 50, '2026-03-01 10:44:17', '2026-05-06 09:49:09');
INSERT INTO `person` VALUES (52, '刘禅', '字公嗣', '蜀国', '刘备之子，于刘备去世后继位成为蜀国皇帝，军国大事先后全权委任于诸葛亮、蒋琬等人，自己没有什么表现。诸葛亮等贤臣相继去世后，刘禅无力把持国政，宦官黄皓开始专权，蜀国逐渐衰败。后魏国大举伐蜀，刘禅投降，举家迁往洛阳，被封为安乐县公，几年后去世。', '/api/uploads/images/20260301/365fcf47e5ba40db9ff9fda11c6bcf4a.png', 49, '2026-03-01 10:44:17', '2026-05-06 09:48:39');
INSERT INTO `person` VALUES (53, '孙尚香', NULL, '吴国', '孙夫人，吴郡富春（今浙江省杭州市富阳区）人，东汉末年孙策 、孙权之妹，曾为左将军刘备之妻。史书《三国志》称之为孙夫人。民间戏剧称之为孙尚香。孙夫人出生在江东望族孙家，自幼便与族中子弟一起习得弓马 。建安十四年，孙权因为畏惧刘备，所以进献当时二十岁左右的妹妹给当时四十九岁的刘备来巩固关系。 孙夫人才智敏捷， 刚强勇猛，有她兄长们的风范，身边的一百多个侍婢，个个都执刀守卫在她身边。即便是刘备这等人物，每次进入内房时，也都感到害怕恐惧。法正因为这个缘故劝说刘备与孙夫人保持距离。 \n孙夫人依仗自己是孙权的妹妹骄横跋扈，她多次率领着从吴国带来的吏兵，纵横不法 。后来，刘备在荆州市公安城西的孱陵（今湖北省荆州市公安县）建了一座城，称作“孱陵城”或“孙夫人城”，让孙夫人与她的侍女及卫队住在一起。 建安十六年（211年），刘备入蜀，孙权于是派遣大船迎接妹妹回吴，孙夫人打算将刘禅一并带走，幸得诸葛亮及时派遣牙门将军赵云和张飞一起在江上拦截，方重夺刘禅，从此她一去不返，杳无音讯。三年后（214年）刘备定益州后，正式改娶吴懿之妹为正室，此后事迹不详。《三国志》中也再没记载过孙夫人回吴后所发生的事情。 [8-9]', '/api/uploads/images/20260301/8c543e829769458fae06204528484572.png', 48, '2026-03-01 10:44:17', '2026-05-05 15:43:07');
INSERT INTO `person` VALUES (54, '大乔', NULL, '吴国', '大乔（生卒年不详），庐江郡皖县（今安徽省潜山市）人，东汉末年江东孙策的夫人，本姓“桥”，小说《三国演义》误作“乔”，因为同时还有一个妹妹嫁给周瑜，为了进行区分，姐姐习惯称作“大乔（桥）”。', '/api/uploads/images/20260301/fb330e55711a49948dc93418095da17d.png', 47, '2026-03-01 10:44:17', '2026-05-05 15:40:53');
INSERT INTO `person` VALUES (55, '小乔', NULL, '吴国', '父桥国老德尊于时。小桥国色流离、资貌绝伦。建安三年，周瑜协策攻皖，拔之。纳小桥。后人谓英雄美女，天做之合。', '/api/uploads/images/20260301/d591de222af048a79df96f14a14d8bbe.png', 46, '2026-03-01 10:44:17', '2026-05-05 15:39:12');
INSERT INTO `person` VALUES (56, '貂蝉', NULL, '东汉', '虚构人物，出自民间传说', '/api/uploads/images/20260301/461296de285c477a9ed7372538acdfc4.png', 45, '2026-03-01 10:44:17', '2026-05-05 15:38:23');
INSERT INTO `person` VALUES (57, '蔡文姬', '字琰', '东汉', '蔡文姬（生卒年不详），名琰，字文姬。陈留郡圉县（今河南开封杞县圉镇）人 ，东汉末年女性文学家，文学家蔡邕之女。博学多才，擅长文学、音乐、书法。初嫁于卫仲道，丈夫死后回家。东汉末中原大乱诸侯割据，原本归降汉朝的南匈奴趁机叛乱，蔡文姬为匈奴左贤王所掳，生育两个孩子。曹操统一北方后，花费重金赎回，嫁给董祀。', '/api/uploads/images/20260301/b801c6417f374709bdaabc3b2c49425e.png', 44, '2026-03-01 10:44:17', '2026-05-05 15:37:45');
INSERT INTO `person` VALUES (58, '甄夫人', NULL, '魏国', '文昭甄皇后183年1月26日—221年8月4日，名不明，史称甄夫人，中山无极（今河北省无极县）人 ，上蔡令甄逸之女。魏文帝曹丕的妻子，魏明帝曹叡的生母。甄氏三岁丧父。建安年间（196年—220年），袁绍为次子袁熙娶之为妻。建安四年（199年），袁熙出任幽州刺史，甄氏留在冀州侍奉袁绍的妻子刘氏。建安九年（204年），曹操率军攻下邺城，甄氏被曹丕所纳，擅宠数年，生下儿子曹叡和女儿曹氏（即东乡公主）。 延康元年（220年），曹丕继位魏王，六月率军南征，甄氏被留在邺城。同年十月，曹丕称帝，山阳公刘协进献二女为曹丕妃嫔，后宫中文德郭皇后、李贵人和阴贵人都得到宠幸 。甄氏愈发失意，流露出一些怨恨的话语，曹丕大怒，黄初二年（221年）六月，遣使赐死甄氏，葬于邺城。 黄初七年（226年），其子曹叡即位后，追谥为文昭皇后。太和四年（230年），魏明帝曹叡将甄氏改葬于朝阳陵。 据载甄皇后贤德出众，文才不凡，有《甄皇后诗选》，其中《塘上行》堪称乐府诗歌代表，至今流传 。被后世尊称为十二花神之水仙花花神。', '/api/uploads/images/20260301/c56cb68f41e84939b58ae475ef7e75ca.png', 43, '2026-03-01 10:44:17', '2026-05-05 15:36:18');
INSERT INTO `person` VALUES (59, '步练师', NULL, '吴国', '虚构人物。', '/api/uploads/images/20260301/af7d36d2ccba402997ae06d0315813ea.png', 42, '2026-03-01 10:44:17', '2026-05-05 15:33:04');
INSERT INTO `person` VALUES (60, '吴国太', NULL, '吴国', '虚构人物，出自三国演义。', '/api/uploads/images/20260301/07ebf3c074a848a89eb4dad665199738.png', 41, '2026-03-01 10:44:17', '2026-05-05 15:32:43');
INSERT INTO `person` VALUES (61, '黄承彦', NULL, '蜀国', '沔南名士。承彦高爽开列，其女嫁予诸葛亮为妻。根据《黄承彦碑》拓本推测，其卒于建安二十三年。', '/api/uploads/images/20260301/94d6f299bf514430b895c473b4b1279f.png', 40, '2026-03-01 10:44:17', '2026-05-05 15:32:10');
INSERT INTO `person` VALUES (62, '司马徽', '水镜先生', '蜀国', '清雅善知人。刘备访士于徽，徽推荐诸葛亮、庞统。时庞德公称其为水镜先生。后为曹操所得，不久病卒。', '/api/uploads/images/20260301/46cf165e9de84044abd81e8dafe2456a.png', 36, '2026-03-01 10:44:17', '2026-05-05 15:31:15');
INSERT INTO `person` VALUES (63, '华佗', '字元化', '魏国', '名医。游学徐土，兼通数经。沛相陈圭举孝廉，太尉黄琬辟，皆不就。晓养性之术，时人以为年且百岁而貌有壮容。又精方药，其疗疾，合汤不过数种，心解分剂，不复称量，煮熟便饮，语其节度，舍去辄愈。一生行医，创五禽戏。后因不愿为曹操治病为操所杀。及后爱子仓舒病因，太祖叹曰：“吾悔杀华佗，令此儿强死也。”', '/api/uploads/images/20260301/c4d9284e70fc4c47a819a00c77432663.png', 38, '2026-03-01 10:44:17', '2026-05-05 15:31:41');
