-- ----------------------------
-- Table structure for ai_question_record
-- ----------------------------
DROP TABLE IF EXISTS `ai_question_record`;
CREATE TABLE `ai_question_record`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '记录唯一标识',
  `user_id` int NOT NULL COMMENT '提问用户ID',
  `conversation_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '会话ID（用于多轮对话）',
  `turn_no` int NOT NULL DEFAULT 1 COMMENT '会话内轮次，从1开始',
  `question_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '用户提问内容',
  `question_type` tinyint NOT NULL DEFAULT 1 COMMENT '提问类型：1-文字，2-语音',
  `answer_content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT 'AI 应答结果',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '提问时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
  INDEX `idx_conversation`(`user_id` ASC, `conversation_id` ASC, `turn_no` ASC) USING BTREE,
  CONSTRAINT `fk_ai_question_user` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 6527 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI提问记录表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of ai_question_record
-- ----------------------------

-- ----------------------------
-- Table structure for ai_question_resource
-- ----------------------------
DROP TABLE IF EXISTS `ai_question_resource`;
CREATE TABLE `ai_question_resource`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `question_id` int NOT NULL COMMENT '提问记录ID',
  `target_type` tinyint NOT NULL COMMENT '资源类型：1-人物，2-事件，3-史料，4-典故',
  `target_id` int NOT NULL COMMENT '关联资源ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_question_id`(`question_id` ASC) USING BTREE,
  INDEX `idx_target`(`target_type` ASC, `target_id` ASC) USING BTREE,
  CONSTRAINT `fk_ai_res_question` FOREIGN KEY (`question_id`) REFERENCES `ai_question_record` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'AI答疑关联表表' ROW_FORMAT = DYNAMIC;

