-- ----------------------------
-- Table structure for forum_topic
-- ----------------------------
DROP TABLE IF EXISTS `forum_topic`;
CREATE TABLE `forum_topic`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主题唯一标识',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主题标题',
  `user_id` int NOT NULL COMMENT '发布用户ID',
  `category` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '主题分类（战役讨论、人物解读、史料研究等）',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主题正文',
  `cover_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '封面图链接',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：1-正常，0-关闭，2-违规隐藏',
  `view_count` int NOT NULL DEFAULT 0 COMMENT '浏览量',
  `reply_count` int NOT NULL DEFAULT 0 COMMENT '回复数',
  `like_count` int NOT NULL DEFAULT 0 COMMENT '点赞数',
  `top_status` tinyint NOT NULL DEFAULT 0 COMMENT '是否置顶：1-置顶，0-普通',
  `essence_status` tinyint NOT NULL DEFAULT 0 COMMENT '是否精华：1-精华，0-普通',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '发布时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_top_sort`(`top_status` ASC, `create_time` ASC) USING BTREE,
  CONSTRAINT `fk_forum_topic_user` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '论坛主题表' ROW_FORMAT = DYNAMIC;

