DROP TABLE IF EXISTS `person_event`;
CREATE TABLE `person_event`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `person_id` int NOT NULL COMMENT '人物ID',
  `event_id` int NOT NULL COMMENT '事件ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_person_event`(`person_id` ASC, `event_id` ASC) USING BTREE,
  INDEX `idx_person_id`(`person_id` ASC) USING BTREE,
  INDEX `idx_event_id`(`event_id` ASC) USING BTREE,
  CONSTRAINT `fk_person_event_event` FOREIGN KEY (`event_id`) REFERENCES `event` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_person_event_person` FOREIGN KEY (`person_id`) REFERENCES `person` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 83 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '人物-事件关联表' ROW_FORMAT = DYNAMIC;

