  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_person_literature`(`person_id` ASC, `literature_id` ASC) USING BTREE,
  INDEX `idx_person_id`(`person_id` ASC) USING BTREE,
  INDEX `idx_literature_id`(`literature_id` ASC) USING BTREE,
  CONSTRAINT `fk_person_lit_literature` FOREIGN KEY (`literature_id`) REFERENCES `literature` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_person_lit_person` FOREIGN KEY (`person_id`) REFERENCES `person` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 70 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '人物-史料关联表' ROW_FORMAT = DYNAMIC;

